  1→/**
  2→ * Overdue Status Badge Component
  3→ *
  4→ * Displays visual indicator for vulnerability overdue status.
  5→ * Shows color-coded badges with optional tooltip details.
  6→ *
  7→ * Status Types:
  8→ * - OK (green): Vulnerability within acceptable age threshold
  9→ * - OVERDUE (red): Vulnerability exceeds threshold with no exception
 10→ * - EXCEPTED (blue): Vulnerability has active exception
 11→ *
 12→ * Features:
 13→ * - Color-coded badges using Bootstrap classes
 14→ * - Emoji icons for quick visual identification
 15→ * - Tooltips with detailed information
 16→ * - Optional detailed display for exception reasons
 17→ * - Accessible (not relying solely on color)
 18→ *
 19→ * Related to: Feature 021-vulnerability-overdue-exception-logic
 20→ */
 21→
 22→import React from 'react';
 23→
 24→interface OverdueStatusBadgeProps {
 25→    status: 'OK' | 'OVERDUE' | 'EXCEPTED';
 26→    daysOverdue?: number | null;
 27→    ageInDays?: number;
 28→    exceptionReason?: string | null;
 29→    exceptionEndDate?: string | null;
 30→    showDetails?: boolean;
 31→    size?: 'sm' | 'md' | 'lg';
 32→}
 33→
 34→const OverdueStatusBadge: React.FC<OverdueStatusBadgeProps> = ({
 35→    status,
 36→    daysOverdue,
 37→    ageInDays,
 38→    exceptionReason,
 39→    exceptionEndDate,
 40→    showDetails = false,
 41→    size = 'md'
 42→}) => {
 43→    const getBadgeConfig = () => {
 44→        switch (status) {
 45→            case 'OVERDUE':
 46→                return {
 47→                    className: 'badge scand-critical',
 48→                    icon: '🔴',
 49→                    text: daysOverdue ? `OVERDUE (${daysOverdue}d)` : 'OVERDUE',
 50→                    tooltip: daysOverdue
 51→                        ? `This vulnerability is ${daysOverdue} days past the configured threshold`
 52→                        : 'This vulnerability exceeds the configured age threshold',
 53→                    ariaLabel: `Overdue status: ${daysOverdue || '?'} days over threshold`
 54→                };
 55→            case 'EXCEPTED':
 56→                const endDate = exceptionEndDate ? new Date(exceptionEndDate).toLocaleDateString() : 'unknown date';
 57→                return {
 58→                    className: 'badge scand-medium',
 59→                    icon: '🛡️',
 60→                    text: 'EXCEPTED',
 61→                    tooltip: exceptionReason
 62→                        ? `Excepted until ${endDate}: ${exceptionReason}`
 63→                        : `This vulnerability has an active exception until ${endDate}`,
 64→                    ariaLabel: `Excepted status: Exception active until ${endDate}`
 65→                };
 66→            case 'OK':
 67→            default:
 68→                return {
 69→                    className: 'badge scand-success',
 70→                    icon: '✅',
 71→                    text: 'OK',
 72→                    tooltip: ageInDays
 73→                        ? `This vulnerability is ${ageInDays} days old, within the acceptable threshold`
 74→                        : 'This vulnerability is within the acceptable age threshold',
 75→                    ariaLabel: `OK status: Within acceptable age threshold`
 76→                };
 77→        }
 78→    };
 79→
 80→    const config = getBadgeConfig();
 81→    
 82→    // Size classes
 83→    const sizeClass = {
 84→        'sm': 'badge-sm',
 85→        'md': '',
 86→        'lg': 'badge-lg'
 87→    }[size];
 88→
 89→    return (
 90→        <div className="d-inline-block">
 91→            <span
 92→                className={`${config.className} ${sizeClass}`}
 93→                data-bs-toggle="tooltip"
 94→                data-bs-placement="top"
 95→                title={config.tooltip}
 96→                style={{ cursor: 'help', fontWeight: 500 }}
 97→                aria-label={config.ariaLabel}
 98→                role="status"
 99→            >
100→                <span aria-hidden="true">{config.icon}</span>{' '}
101→                {config.text}
102→            </span>
103→            
104→            {showDetails && status === 'EXCEPTED' && exceptionReason && (
105→                <div 
106→                    className="small text-muted mt-1" 
107→                    style={{ fontSize: '0.75rem', maxWidth: '300px' }}
108→                    role="note"
109→                >
110→                    <i className="bi bi-info-circle me-1"></i>
111→                    {exceptionReason}
112→                    {exceptionEndDate && (
113→                        <div className="mt-1">
114→                            <i className="bi bi-calendar-event me-1"></i>
115→                            Until: {new Date(exceptionEndDate).toLocaleDateString()}
116→                        </div>
117→                    )}
118→                </div>
119→            )}
120→        </div>
121→    );
122→};
123→
124→export default OverdueStatusBadge;
