108→export async function getCurrentVulnerabilities(
109→    severity?: string,
110→    system?: string,
111→    exceptionStatus?: string,
112→    product?: string,
113→    adDomain?: string,
114→    cloudAccountId?: string,
115→    page?: number,
116→    size?: number,
117→    sort?: string,
118→    sortDir?: string
119→): Promise<PaginatedVulnerabilitiesResponse> {
120→    const params = new URLSearchParams();
121→    if (severity) params.append('severity', severity);
122→    if (system) params.append('system', system);
123→    if (exceptionStatus) params.append('exceptionStatus', exceptionStatus);
124→    if (product) params.append('product', product);
125→    if (adDomain) params.append('adDomain', adDomain);
126→    if (cloudAccountId) params.append('cloudAccountId', cloudAccountId);
127→    if (page !== undefined) params.append('page', page.toString());
128→    if (size !== undefined) params.append('size', size.toString());
129→    if (sort) params.append('sort', sort);
130→    if (sortDir) params.append('sortDir', sortDir);
131→
132→    const queryString = params.toString();
133→    const url = `/api/vulnerabilities/current${queryString ? `?${queryString}` : ''}`;
