import org.hibernate.annotations.CreationTimestamp
import org.hibernate.annotations.UpdateTimestamp
import java.time.LocalDateTime

/**
 * VulnerabilityConfig entity representing global vulnerability management settings.
 *
 * This is a singleton entity (only one record exists in the database).
 * Stores configuration for vulnerability overdue tracking and remediation SLAs.
 *
 * Related to: Feature 021-vulnerability-overdue-exception-logic
 *
 * @property id Unique identifier (always 1 in practice)
 * @property reminderOneDays Days threshold after which vulnerabilities are considered overdue
 * @property updatedBy Username of last person who updated the configuration
 * @property createdAt When the configuration was first created (auto-generated)
 * @property updatedAt When the configuration was last updated (auto-updated)
 */
@Entity
@Table(name = "vulnerability_config")
@Serdeable
data class VulnerabilityConfig(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    val id: Long? = null,

    /**
     * "Reminder One" threshold in days.
     * Vulnerabilities older than this are considered overdue (if not excepted).
     * Default: 30 days
     * Valid range: 1-365 days
     */
    @Column(name = "reminder_one_days", nullable = false)
    @Min(1)
    @Max(365)
    var reminderOneDays: Int = 30,

    /**
     * Username of the administrator who last updated this configuration
     */
    @Column(name = "updated_by", length = 255)
    var updatedBy: String? = null,

    @CreationTimestamp
    @Column(name = "created_at", nullable = false, updatable = false)
    val createdAt: LocalDateTime? = null,

    @UpdateTimestamp
    @Column(name = "updated_at", nullable = false)
    var updatedAt: LocalDateTime? = null
) {
    override fun toString(): String {
        return "VulnerabilityConfig(id=$id, reminderOneDays=$reminderOneDays, updatedBy='$updatedBy')"
    }

    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is VulnerabilityConfig) return false
        return id != null && id == other.id
    }

    override fun hashCode(): Int {
        return id?.hashCode() ?: 0
    }
}

val dedupCount = beforeDedup - vulnsWithCve.size
if (dedupCount > 0) {
    log.info("Deduplicated {} duplicate (CVE, product) entries for asset '{}' ({} -> {} unique)",
        dedupCount, asset.name, beforeDedup, vulnsWithCve.size)
}

// Create and save vulnerability records in chunks (T021)
// Entity creation is merged into the chunk loop so only chunkSize entities live at any time,
// rather than creating all entities upfront (which holds O(all_vulns) in memory).
val importTimestamp = LocalDateTime.now()
var vulnerabilitiesWithPatchDateCount = 0
var totalCreated = 0
val chunkSize = 500

if (vulnsWithCve.isNotEmpty()) {
    val totalChunks = (vulnsWithCve.size + chunkSize - 1) / chunkSize
    vulnsWithCve.chunked(chunkSize).forEachIndexed { index, dtoChunk ->
        val entities = dtoChunk.map { vulnDto ->
            if (vulnDto.patchPublicationDate != null) {
                vulnerabilitiesWithPatchDateCount++
            }

            // Calculate scan timestamp and days open
            val (scanTimestamp, daysOpenText) = if (vulnerabilitySettings.usePatchPublicationDate && vulnDto.patchPublicationDate != null) {
                val patchDate = vulnDto.patchPublicationDate
                val daysFromPatch = ChronoUnit.DAYS.between(patchDate, importTimestamp).toInt()
                val daysText = if (daysFromPatch == 1) "1 day" else "$daysFromPatch days"
                log.trace("Using patch publication date for CVE {}: patch_date={}, days_from_patch={}",
                    vulnDto.cveId, patchDate, daysFromPatch)
                Pair(patchDate, daysText)
            } else {
                val discoveryTimestamp = importTimestamp.minusDays(vulnDto.daysOpen.toLong())
                val daysText = "${vulnDto.daysOpen} days"
                Pair(discoveryTimestamp, daysText)
            }

            Vulnerability(
                asset = asset,
                vulnerabilityId = vulnDto.cveId,
                cvssSeverity = vulnDto.severity,
                vulnerableProductVersions = vulnDto.affectedProduct,
                daysOpen = daysOpenText,
                scanTimestamp = scanTimestamp,
                importTimestamp = importTimestamp,
                patchPublicationDate = vulnDto.patchPublicationDate
            )
        }

        vulnerabilityRepository.saveAll(entities)
        totalCreated += entities.size

        // Flush/clear for all but the last chunk to keep Hibernate L1 cache bounded
        if (index < totalChunks - 1) {
            entityManager.flush()
            entityManager.clear()
            entityManager.merge(asset)
            log.trace("Saved vulnerability chunk {}/{} for asset '{}'",
                index + 1, totalChunks, asset.name)
        }
    }
    log.debug("Created {} new vulnerabilities for asset '{}' ({} with patch publication date)",
        totalCreated, asset.name, vulnerabilitiesWithPatchDateCount)
}

return ServerImportResult(
    assetCreated = isNewAsset,
    vulnerabilitiesImported = totalCreated,
    vulnerabilitiesSkipped = skippedCount,
    vulnerabilitiesWithPatchDate = vulnerabilitiesWithPatchDateCount

